func DecodeTHUMBBranch(op uint16) bool {

	switch {
	case isthumbSWI(op):
		return false
	case isThumbAddSub(op):
		return true
	case isThumbShift(op):
		return true
	case isThumbImm(op):
		return true
	case isThumbAlu(op):
		return true
	case isThumbHiReg(op):

		var (
			inst = (op >> 8) & 0b11
			mSBd = (op>>7)&1 != 0
			rd   = op & 0x7
		)

		if inst != 3 && mSBd {
			rd |= 0b1000
		}

		if inst == 3 || rd == PC {
			return false
		}

		return true
	case isLSHalf(op):
		return true
	case isThumbSdt(op):
		return true
	case isLPC(op):
		return true
	case isLSImm(op):
		return true
	case isPushPop(op):
		pclr := (op>>8)&1 != 0
		pop := (op>>11)&1 != 0
		if pop && pclr {
			return false
		}

		return true
	case isRelative(op):
		return true
	case isThumbB(op):
		return false
	case isJumpCall(op):
		return false
	case isStack(op):
		return true
	case isLongBranch(op):
		return false
	case isShortLongBranch(op):
		return false
	case isLSSP(op):
		return true
	case isMulti(op):

		ldmia := (op>>11)&1 != 0
		rlist := op & 0xFF

		if ldmia && rlist == 0 {
			return false
		}

		return true
	}

	return false
}
